const rCI=(it,idx)=>{if(it.tipo==="check")return(<div key={idx} style={{padding:"10px 0",borderBottom:"1px solid #f0eeea"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12}}><div style={{flex:1}}><div style={{fontSize:13,fontWeight:500,color:tp2}}>{it.tarea}</div>{it.desc&&<div style={{fontSize:12,color:tt2,marginTop:2}}>{it.desc}</div>}</div><div style={{display:"flex",gap:4,flexShrink:0}}>{["OK","Obs.","N/A"].map(r=><button key={r} onClick={()=>uI(idx,"resultado",r)} style={{padding:"4px 10px",fontSize:12,fontWeight:500,borderRadius:6,cursor:"pointer",border:`1px solid ${it.resultado===r?(r==="OK"?ac:r==="Obs."?"#ba7517":"#888"):brd}`,background:it.resultado===r?(r==="OK"?acL:r==="Obs."?"#faeeda":"#f1efe8"):"#fff",color:it.resultado===r?(r==="OK"?acD:r==="Obs."?"#633806":"#444"):tt2}}>{r}</button>)}</div></div>{it.resultado==="Obs."&&<input type="text" placeholder="Detallar..." value={it.observacion} onChange={e=>uI(idx,"observacion",e.target.value)} style={{...inp,marginTop:8,fontSize:13}}/>}</div>);if(it.tipo==="numero")return(<div key={idx} style={{padding:"10px 0",borderBottom:"1px solid #f0eeea"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12}}><div style={{flex:1}}><div style={{fontSize:13,fontWeight:500,color:tp2}}>{it.tarea}</div>{it.desc&&<div style={{fontSize:12,color:tt2,marginTop:2}}>{it.desc}</div>}</div><div style={{display:"flex",alignItems:"center",gap:6}}><input type="number" step="any" placeholder="—" value={it.valor} onChange={e=>uI(idx,"valor",e.target.value)} style={{width:90,padding:"6px 10px",border:`1px solid ${it.valor?ac:brd}`,borderRadius:6,fontSize:14,fontWeight:500,textAlign:"right",outline:"none",background:it.valor?acL:"#fff",color:tp2}}/><span style={{fontSize:12,fontWeight:500,color:it.valor?acD:tt2,minWidth:32}}>{it.unidad}</span></div></div></div>);return(<div key={idx} style={{padding:"10px 0",borderBottom:"1px solid #f0eeea"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:12}}><div style={{fontSize:13,fontWeight:500,color:tp2}}>{it.tarea}</div><input type="text" placeholder="Ingresar..." value={it.valor} onChange={e=>uI(idx,"valor",e.target.value)} style={{width:160,padding:"6px 10px",border:`1px solid ${it.valor?ac:brd}`,borderRadius:6,fontSize:13,outline:"none",background:it.valor?acL:"#fff",color:tp2}}/></div></div>)};

const rInfo=()=>(<div>{eq&&<div style={{...card,background:acL,borderColor:ac+"33"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}><div style={{fontSize:16,fontWeight:600,color:acD,fontFamily:"monospace"}}>{ot.numero_ot}</div><span style={{fontSize:12,padding:"4px 10px",borderRadius:20,background:"#faeeda",color:"#ba7517",fontWeight:500}}>{ot.estado}</span></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px 16px",fontSize:13,color:acD}}><div><span style={{opacity:0.6}}>Cliente:</span> {cli?.nombre_fantasia}</div><div><span style={{opacity:0.6}}>Tipo:</span> {ot.tipo_servicio}</div><div><span style={{opacity:0.6}}>Equipo:</span> {eq.modelo} — {eq.marca}</div><div><span style={{opacity:0.6}}>Serie:</span> {eq.sn_equipo||"N/D"}</div><div><span style={{opacity:0.6}}>Tipo eq.:</span> {eq.tipo_equipo} — {eq.clasificacion2}</div>{eq.ubicacion_equipo&&<div><span style={{opacity:0.6}}>Ubicación:</span> {eq.ubicacion_equipo}</div>}{eq.tension_tubo&&<div><span style={{opacity:0.6}}>Tensión tubo:</span> {eq.tension_tubo}</div>}{eq.corriente_tubo&&<div><span style={{opacity:0.6}}>Corriente tubo:</span> {eq.corriente_tubo}</div>}</div></div>}{libre&&<div style={{padding:"10px 14px",background:"#faeeda",borderRadius:8,fontSize:13,color:"#633806"}}>Servicio {ot.tipo_servicio.toLowerCase()} — formulario libre</div>}</div>);

const rChk=()=>(<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}><span style={{fontSize:13,color:ts2}}>{done}/{tot}</span><div style={{width:120,height:6,background:"#e8e6df",borderRadius:3,overflow:"hidden"}}><div style={{width:`${tot?((done/tot)*100):0}%`,height:"100%",background:ac,borderRadius:3,transition:"width 0.3s"}}/></div></div>{secs.map(sec=>{const items=chk.filter(i=>i.seccion===sec);const si=chk.indexOf(items[0]);const dn=items.filter(i=>i.tipo==="check"?i.resultado:i.valor).length;const op=expS[sec];return(<div key={sec} style={{...card,padding:0,overflow:"hidden"}}><button onClick={()=>tgS(sec)} style={{width:"100%",padding:"14px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",background:"none",border:"none",cursor:"pointer",borderBottom:op?`1px solid ${brd}`:"none"}}><span style={{fontSize:14,fontWeight:500,color:tp2}}>{sec}</span><span style={{fontSize:12,color:dn===items.length?ac:tt2}}>{dn}/{items.length} {op?"\u25B2":"\u25BC"}</span></button>{op&&<div style={{padding:"0 20px 10px"}}>{items.map((it,i)=>rCI(it,si+i))}</div>}</div>)})}</div>);

